class Solution:
    def originalDigits(self, s: str) -> str:
        counts = [0] * 10
        for char in s:
            if char == 'z':
                counts[0] += 1
            elif char == 'w':
                counts[2] += 1
            elif char == 'u':
                counts[4] += 1
            elif char == 'x':
                counts[6] += 1
            elif char == 'g':
                counts[8] += 1
            elif char == 'f':
                counts[5] += 1
            elif char == 'h':
                counts[3] += 1
            elif char == 'i':
                counts[9] += 1
            elif char == 'o':
                counts[1] += 1
            elif char == 'n':
                counts[7] += 1
        result = ''.join(map(str, counts))
        return ''.join(sorted(result))
